package com.tarunguptaraja.coldemailer.util

import android.content.Context
import android.content.SharedPreferences

object PreferenceHelper {

 private const val PREF_NAME = "ColdEmailerPrefs"

 object Keys {
 const val USER_NAME = "user_name"
 const val USER_EMAIL = "user_email"
 const val COMPANY_NAME = "company_name"
 const val POSITION = "position"
 const val TEMPLATE_ID = "template_id"
 const val IS_FIRST_LAUNCH = "is_first_launch"
 const val LAST_UPLOADED_RESUME = "last_uploaded_resume"
 }

 private fun getPreferences(context: Context): SharedPreferences {
 return context.getSharedPreferences(PREF_NAME, Context.MODE_PRIVATE)
 }

 fun putString(context: Context, key: String, value: String) {
 getPreferences(context).edit().putString(key, value).apply()
 }

 fun getString(context: Context, key: String, defaultValue: String = ""): String {
 return getPreferences(context).getString(key, defaultValue) ?: defaultValue
 }

 fun putInt(context: Context, key: String, value: Int) {
 getPreferences(context).edit().putInt(key, value).apply()
 }

 fun getInt(context: Context, key: String, defaultValue: Int = 0): Int {
 return getPreferences(context).getInt(key, defaultValue)
 }

 fun putBoolean(context: Context, key: String, value: Boolean) {
 getPreferences(context).edit().putBoolean(key, value).apply()
 }

 fun getBoolean(context: Context, key: String, defaultValue: Boolean = false): Boolean {
 return getPreferences(context).getBoolean(key, defaultValue)
 }

 fun remove(context: Context, key: String) {
 getPreferences(context).edit().remove(key).apply()
 }

 fun clear(context: Context) {
 getPreferences(context).edit().clear().apply()
 }

 // Convenience methods for user data
 fun saveUserInfo(context: Context, name: String, email: String) {
 putString(context, Keys.USER_NAME, name)
 putString(context, Keys.USER_EMAIL, email)
 }

 fun saveResumePath(context: Context, path: String) {
 putString(context, Keys.LAST_UPLOADED_RESUME, path)
 }

 fun getResumePath(context: Context): String {
 return getString(context, Keys.LAST_UPLOADED_RESUME)
 }
}
