)\n }\n\n fun getBoolean(context: Context, key: String, defaultValue: Boolean = false): Boolean {\n return getPreferences(context).getBoolean(key, defaultValue)\n }\n\n fun remove(context: Context, key: String) {\n getPreferences(context).edit().remove(key).apply()\n }\n\n fun clear(context: Context) {\n getPreferences(context).edit().clear().apply()\n }\n\n // ============ PROFILE DATA METHODS ============\n\n fun saveProfile(context: Context, profile: UserProfile) {\n val editor = getPreferences(context).edit()\n editor.putString(Keys.USER_NAME, profile.name)\n editor.putString(Keys.USER_EMAIL, profile.email)\n editor.putString(Keys.COMPANY_NAME, profile.companyName)\n editor.putString(Keys.POSITION, profile.position)\n editor.putString(Keys.LAST_UPLOADED_RESUME, profile.resumePath)\n editor.putInt(Keys.TEMPLATE_ID, profile.templateId)\n editor.putBoolean(Keys.PROFILE_COMPLETE, true)\n editor.apply()\n }\n\n fun getProfile(context: Context): UserProfile {\n val prefs = getPreferences(context)\n return UserProfile(\n name = prefs.getString(Keys.USER_NAME, \"\") ?: \"\",\n email = prefs.getString(Keys.USER_EMAIL, \"\") ?: \"\",\n companyName = prefs.getString(Keys.COMPANY_NAME, \"\") ?: \"\",\n position = prefs.getString(Keys.POSITION, \"\") ?: \"\",\n resumePath = prefs.getString(Keys.LAST_UPLOADED_RESUME, \"\") ?: \"\",\n templateId = prefs.getInt(Keys.TEMPLATE_ID, 0)\n )\n }\n\n fun isProfileComplete(context: Context): Boolean {\n return getBoolean(context, Keys.PROFILE_COMPLETE, false)\n }\n\n // Individual field getters for convenience\n fun getUserName(context: Context): String = getString(context, Keys.USER_NAME)\n fun getUserEmail(context: Context): String = getString(context, Keys.USER_EMAIL)\n fun getCompanyName(context: Context): String = getString(context, Keys.COMPANY_NAME)\n fun getPosition(context: Context): String = getString(context, Keys.POSITION)\n fun getResumePath(context: Context): String = getString(context, Keys.LAST_UPLOADED_RESUME)\n fun getTemplateId(context: Context): Int = getInt(context, Keys.TEMPLATE_ID)\n\n // Legacy convenience methods\n fun saveUserInfo(context: Context, name: String, email: String) {\n putString(context, Keys.USER_NAME, name)\n putString(context, Keys.USER_EMAIL, email)\n }\n\n fun saveResumePath(context: Context, path: String) {\n putString(context, Keys.LAST_UPLOADED_RESUME, path)\n }\n}", "instructions": "Add a UserProfile data class and comprehensive profile saving/loading methods including saveProfile(), getProfile(), and individual field getters", "target_file": "app/src/main/java/com/tarunguptaraja/coldemailer/util/PreferenceHelper.kt"}"}}]},{"role":"tool","name":"edit_file","tool_call_id":" functions.edit_file:1","content":"The apply model made the following changes to the file:

